class Solution:
    def cloneGraph(self, node):
        clones = {}
        def clone(current):
            if not current:
                return None
            if current in clones:
                return clones[current]
            copy = Node(current.val, [])
            clones[current] = copy
            copy.neighbors = [clone(neighbor) for neighbor in current.neighbors]
            return copy
        return clone(node)
